import{_ as o,o as t,c as a,a2 as d}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"ECodex 1.0.3 发布说明","description":"","frontmatter":{},"headers":[],"relativePath":"release-notes/1.0.3.md","filePath":"release-notes/1.0.3.md","lastUpdated":null}'),l={name:"release-notes/1.0.3.md"};function r(i,e,s,n,c,h){return t(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="ecodex-1-0-3-发布说明" tabindex="-1">ECodex 1.0.3 发布说明 <a class="header-anchor" href="#ecodex-1-0-3-发布说明" aria-label="Permalink to &quot;ECodex 1.0.3 发布说明&quot;">​</a></h1><p>ECodex 1.0.3 聚焦 Windows 桌面生命周期一致性：关闭按钮明确退出主进程，重复启动只激活已有窗口，最小化后仍保留任务栏入口并继续后台运行。</p><h2 id="推荐下载" tabindex="-1">推荐下载 <a class="header-anchor" href="#推荐下载" aria-label="Permalink to &quot;推荐下载&quot;">​</a></h2><table tabindex="0"><thead><tr><th>产物</th><th>适用场景</th><th>说明</th></tr></thead><tbody><tr><td><code>ecodex-win-x64-sc</code></td><td>大多数 Windows 10/11 用户</td><td>self-contained app 目录，不需要共享 .NET runtime。</td></tr><tr><td><code>ecodex-cli-win-x64</code></td><td>自动化脚本和 CI</td><td>仅命令行包，提供 <code>ecodex</code> 命令。</td></tr><tr><td>Inno Setup 安装器</td><td>传统桌面安装</td><td>简体中文安装 / 卸载界面，创建快捷方式，卸载保留 <code>%USERPROFILE%\\.ecodex</code>。</td></tr><tr><td>MSIX 包</td><td>企业分发</td><td>适合受管环境。</td></tr></tbody></table><p>详细步骤见 <a href="./../installation">安装</a>。</p><h2 id="窗口生命周期" tabindex="-1">窗口生命周期 <a class="header-anchor" href="#窗口生命周期" aria-label="Permalink to &quot;窗口生命周期&quot;">​</a></h2><ul><li><strong>关闭按钮会退出</strong>：点击右上角 X 会保存当前会话并退出 <code>ecodex-app</code> 主进程；daemon 托管终端是否保留仍由 <code>PreserveDaemonSessionsOnClose</code> 决定。</li><li><strong>最小化保留任务栏</strong>：最小化后 ECodex 继续后台运行，任务栏按钮仍保留；再次点击任务栏图标会把窗口带回前台。</li><li><strong>单实例保护</strong>：<code>ecodex-app</code> 只允许一个长期运行实例；重复启动会通过 <code>Global\\ECodexMainApp</code> 互斥体退出新进程，并请求已有窗口聚焦。</li><li><strong>任务栏激活一致</strong>：安装版快捷方式和主进程统一使用 AppUserModelID <code>ECodex.App</code>，固定任务栏图标、任务栏按钮和托盘入口都指向同一个已有窗口。</li></ul><h2 id="运维与维护者改进" tabindex="-1">运维与维护者改进 <a class="header-anchor" href="#运维与维护者改进" aria-label="Permalink to &quot;运维与维护者改进&quot;">​</a></h2><ul><li><code>scripts/smoke-toast-activation.ps1</code> 覆盖 AppUserModelID 与任务栏 / Toast 激活检查，便于发布前记录 Windows 手动 smoke 证据。</li><li>文档、spec 与 source tests 已同步关闭、最小化、单实例和后台运行语义，避免后续回退到“最小化隐藏到托盘”的旧行为。</li></ul><h2 id="升级注意事项" tabindex="-1">升级注意事项 <a class="header-anchor" href="#升级注意事项" aria-label="Permalink to &quot;升级注意事项&quot;">​</a></h2><ul><li>替换文件前建议停止 <code>ecodex-app.exe</code>、<code>ecodex-daemon.exe</code> 和旧终端会话，避免 Windows 文件锁。</li><li>如果从未绑定 AppUserModelID 的裸 exe 路径手动重复启动，系统可能短暂创建启动进程；该进程会立即退出并把已有窗口带回前台。</li><li>安装后运行 <code>ecodex doctor</code> 和 <code>ecodex setup status</code> 检查 PATH、daemon、WebView2、PowerShell hook 与配置目录。</li><li>卸载与更新默认保留 <code>%USERPROFILE%\\.ecodex</code>，不会删除现有 session、resume、command log 或用户 skills。</li></ul><h2 id="发布门槛" tabindex="-1">发布门槛 <a class="header-anchor" href="#发布门槛" aria-label="Permalink to &quot;发布门槛&quot;">​</a></h2><ul><li>发布前仍按 P0 = 0、P1 &lt;= 3 且 P1 必须有 workaround 的门槛验收。</li><li>如果安装、任务栏激活、Toast、WebView2 或 ConPTY 行为异常，优先参考 <a href="./../troubleshooting">故障排查</a> 和 <a href="./../release-readiness">发布就绪</a>。</li></ul><h2 id="更多文档" tabindex="-1">更多文档 <a class="header-anchor" href="#更多文档" aria-label="Permalink to &quot;更多文档&quot;">​</a></h2><ul><li><a href="./../installation">安装</a></li><li><a href="./../getting-started">快速上手</a></li><li><a href="./../cli">命令行</a></li><li><a href="./../session-restore">会话恢复</a></li><li><a href="./../troubleshooting">故障排查</a></li></ul>',15)])])}const x=o(l,[["render",r]]);export{u as __pageData,x as default};
